// InteractionForm.js
import React from "react";
import { useSelector, useDispatch } from "react-redux";

function InteractionForm(){
  const form = useSelector(state => state.form);
  const dispatch = useDispatch();

  const handleChange = (field, value) => {
    dispatch({ type: "UPDATE_FORM", payload: { [field]: value } });
  }

  // Emoji mapping for sentiment
  const sentimentEmoji = {
    positive: "😊",
    neutral: "😐",
    negative: "😞"
  }

  return(
    <div>
      <h2>Log HCP Interaction</h2>

      <input
        placeholder="HCP Name"
        value={form.hcp_name || ""}
        onChange={(e) => handleChange("hcp_name", e.target.value)}
      />
      <input
        placeholder="Interaction Type"
        value={form.interaction_type || ""}
        onChange={(e) => handleChange("interaction_type", e.target.value)}
      />
      <input
        placeholder="Date"
        value={form.date || ""}
        onChange={(e) => handleChange("date", e.target.value)}
      />
      <input
        placeholder="Time"
        value={form.time || ""}
        onChange={(e) => handleChange("time", e.target.value)}
      />
      <textarea
        placeholder="Topics Discussed"
        value={form.topics || ""}
        onChange={(e) => handleChange("topics", e.target.value)}
      />
      <textarea
        placeholder="Outcomes"
        value={form.outcomes || ""}
        onChange={(e) => handleChange("outcomes", e.target.value)}
      />
      <textarea
        placeholder="Follow Up"
        value={form.followup || ""}
        onChange={(e) => handleChange("followup", e.target.value)}
      />

      {/* Sentiment Display */}
      {form.sentiment && (
        <div>
          <strong>Sentiment: </strong>
          <span>{sentimentEmoji[form.sentiment]} {form.sentiment}</span>
        </div>
      )}
    </div>
  )
}

export default InteractionForm;
